      `})]})}const Ug=[{number:"01",title:"THE DIAGNOSIS",body:"Before anything is designed, the business is pulled apart. Category, competition, founder story, audience psychology. The goal: find the one position the brand can own that no one else can claim. Different is better than better.",param:"PHASE 01"},{number:"02",title:"THE SCRIPT",body:"Brand archetypes. Transformation story. Positioning statement. Campaign naming. This is pre-production — the strategic document everything else is built from. No visuals until this is locked.",param:"PHASE 02"},{number:"03",title:"THE PRODUCTION",body:"Visual identity. Photography direction. Ad creative. Content scripts. Campaign assets. The script becomes the film. Every creative decision traces back to strategy.",param:"PHASE 03"},{number:"04",title:"THE LAUNCH",body:"Campaign execution. Meta ads setup. Micro-influencer outreach. KPI tracking. The brand goes live. The movement begins.",param:"PHASE 04"}];function cN({step:t,i:e,total:n}){return s.jsx("div",{className:"anim",style:{borderBottom:e<n-1?"1px solid var(--rule)":"none",width:"100vw",marginLeft:"calc(-50vw + 50%)",paddingLeft:"max(var(--gutter), calc(50vw - var(--max) / 2))",paddingRight:"max(var(--gutter), calc(50vw - var(--max) / 2))"},children:s.jsxs("div",{style:{display:"grid",gridTemplateColumns:"120px 1fr auto",gap:"32px",padding:"28px 0",alignItems:"start"},className:"step-row",children:[s.jsxs("span",{className:"param-label",style:{paddingTop:"4px"},children:["STEP ",t.number]}),s.jsxs("div",{children:[s.jsx("div",{style:{fontFamily:"var(--font-display)",fontSize:"clamp(20px,3vw,36px)",color:"var(--ink)",letterSpacing:"0.02em",lineHeight:1,marginBottom:"12px"},children:t.title}),s.jsx("p",{className:"body body--sm",style:{maxWidth:"540px"},children:t.body})]}),s.jsx("span",{className:"param-label",style:{paddingTop:"4px",textAlign:"right"},children:t.param})]})})}function pN(){const[t,e]=T.useState(!1);return s.jsxs("div",{style:{width:"100vw",marginLeft:"calc(-50vw + 50%)",background:"var(--ink)",paddingLeft:"max(var(--gutter), calc(50vw - var(--max) / 2))",paddingRight:"max(var(--gutter), calc(50vw - var(--max) / 2))",paddingTop:"72px",paddingBottom:"72px"},children:[s.jsx("div",{style:{height:"1px",background:"rgba(240,237,232,0.2)",marginBottom:"28px"}}),s.jsxs("div",{style:{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"32px"},children:[s.jsx("span",{style:{fontFamily:"var(--font-label)",fontSize:"9px",textTransform:"uppercase",letterSpacing:"0.18em",color:"rgba(240,237,232,0.5)"},children:"STOP WASTING YOUR MARKETING BUDGET"}),s.jsx("span",{style:{fontFamily:"var(--font-label)",fontSize:"9px",textTransform:"uppercase",letterSpacing:"0.18em",color:"rgba(240,237,232,0.5)"},children:"LUMINARY / EZRA DOM"})]}),s.jsxs("div",{style:{marginBottom:"32px"},children:[s.jsx("span",{style:{display:"block",fontFamily:"var(--font-display)",fontSize:"clamp(48px, 10vw, 140px)",color:"#F0EDE8",letterSpacing:"0.01em",lineHeight:.9,marginBottom:"0.04em"},children:"MARKETING WITHOUT"}),s.jsx("span",{style:{display:"block",fontFamily:"var(--font-display)",fontSize:"clamp(48px, 10vw, 140px)",color:"#F0EDE8",letterSpacing:"0.01em",lineHeight:.9},children:"A BRAND IS JUST NOISE."})]}),s.jsxs("div",{style:{display:"grid",gridTemplateColumns:"1fr auto",gap:"48px",alignItems:"end"},className:"cta-inner",children:[s.jsx("p",{style:{fontFamily:"var(--font-body)",fontSize:"15px",lineHeight:1.72,color:"rgba(240,237,232,0.72)",maxWidth:"560px"},children:"Most businesses pour money into ads, content, and campaigns before they've built the foundation those things need to work. Strategy first means every marketing dollar goes further — because people already know what you stand for before they see the ad. Build the brand that sticks in people's minds. Then market it."}),s.jsx("a",{href:"mailto:itsezradom@gmail.com?subject=Brand%20Strategy%20Inquiry",onMouseEnter:()=>e(!0),onMouseLeave:()=>e(!1),style:{fontFamily:"var(--font-display)",fontSize:"clamp(18px, 2.2vw, 28px)",letterSpacing:"0.04em",color:t?"var(--ink)":"#F0EDE8",background:t?"#F0EDE8":"transparent",border:"2px solid rgba(240,237,232,0.7)",padding:"20px 36px 22px",lineHeight:1,transition:"all 0.25s ease",whiteSpace:"nowrap",display:"inline-block",textDecoration:"none"},children:"LET'S BUILD YOUR BRAND →"})]}),s.jsx("div",{style:{height:"1px",background:"rgba(240,237,232,0.2)",marginTop:"48px"}})]})}function Wg(){const t=T.useRef(null);return T.useEffect(()=>{if(!t.current)return;const e=Wn(t.current,{trigger:t.current,start:"top 84%"});return()=>e.kill()},[]),s.jsxs("section",{id:"process",ref:t,children:[s.jsxs("div",{className:"wrap",children:[s.jsx("div",{className:"rule anim"}),s.jsxs("div",{className:"meta-row anim",children:[s.jsx("span",{className:"meta-label",children:"04 — THE PROCESS"}),s.jsx("span",{className:"meta-label meta-label--faint",children:"4 PHASES"}),s.jsx("span",{className:"meta-label meta-label--faint",children:"STRATEGY FIRST"})]}),s.jsx("div",{className:"rule anim"}),s.jsxs("div",{style:{padding:"4px 0"},children:[s.jsx("span",{className:"display-line anim",style:{fontSize:"clamp(56px, 13vw, 190px)"},children:"STORY FIRST."}),s.jsx("span",{className:"display-line anim",style:{fontSize:"clamp(56px, 13vw, 190px)"},children:"VISUALS SECOND."})]}),s.jsx("div",{className:"rule anim"}),s.jsx("div",{style:{padding:"24px 0",maxWidth:"720px"},className:"anim",children:s.jsx("p",{className:"body",children:"Most designers ask: what looks good? That's the wrong question. The right question is: what does the audience actually perceive? Strategy starts with the human mind, psychology, archetypes, narrative, and the visuals follow. A brand is not decoration. It is the space between what a business does and what its audience believes about it. Branding is the discipline of closing that gap."})}),s.jsx("div",{className:"rule anim"}),Ug.map((e,n)=>s.jsx(cN,{step:e,i:n,total:Ug.length},e.number)),s.jsx("div",{className:"rule anim"}),s.jsx("div",{style:{padding:"20px 0"},children:s.jsxs("p",{className:"anim",style:{fontFamily:"var(--font-display)",fontSize:"clamp(18px, 2.8vw, 36px)",color:"var(--ink-dim)",letterSpacing:"0.02em",lineHeight:1.2},children:["YOUR BRAND IS YOUR REPUTATION.",s.jsx("br",{}),"BRANDING IS REPUTATION MANAGEMENT."]})}),s.jsx("div",{className:"rule anim"}),s.jsxs("div",{className:"meta-row anim",children:[s.jsx("span",{className:"meta-label meta-label--faint",children:"END PARAMETER 00 – 00"}),s.jsx("span",{className:"meta-label meta-label--faint",children:"SRB IJA–04"})]}),s.jsx("div",{className:"rule anim"})]}),s.jsx(pN,{}),s.jsx("style",{children:`
