      `})]})}const hN="/assets/ezra-about-V7bZuYx5.jpg",Yg=[{label:"STUDIO",value:"LUMINARY / BRAND CAMPAIGN STUDIO, FOUNDER"},{label:"SCOPE",value:"10+ BRANDS BUILT / 20+ LOGO + DESIGN PROJECTS"},{label:"PROJECT 01",value:"SWEATCULTURE / BRAND STRATEGY + IDENTITY + ADVISORY"},{label:"PROJECT 02",value:"TRAILSIDE LEMONADE / BRAND STRATEGY + IDENTITY"},{label:"ACADEMIC",value:"IED MASTERS IN BRAND STRATEGY + MANAGEMENT / ACCEPTED NOV 2026"},{label:"SOCIAL",value:"INSTAGRAM: @ITSEZRADOM_"}],fN=["I'm Ezra Dom. I'm 19 years old, based in BC, Canada, and I'm the founder of Luminary, a brand campaign studio built for founder-led businesses who want to be known for what they actually stand for.","I started in graphic design in 2022 out of curiosity, and it quickly became discipline. I studied typography, hierarchy, color, composition, and psychology obsessively. Design taught me how people see, feel, and decide. But I hit a wall. A client told me to just make it look good, don't worry about the strategy. That was the moment I realized I didn't want to be a pixel pusher for the rest of my career.","I was also watching AI get genuinely good at the visual stuff. I had to be honest with myself. If I stayed focused only on execution, I was building on a foundation that was getting commoditized. I needed to go deeper, into the thinking behind the thinking. Into why brands actually work. Into the psychology of identity, story, and decision-making.","That's what pushed me into brand strategy. Into Marty Neumeier's positioning frameworks, Jungian archetypes, and the fundamental idea that great brands don't sell products. They broker identity. They help people become someone. I've since built 10+ brands and worked on 20+ logo and design projects, and I'm building Luminary to bring that level of thinking to more founders who deserve it.","I want to be the kind of person people trust and listen to, not because of my visual eye, but because of my judgement. That's the difference between a designer and a strategist."];function Gg(){const t=T.useRef(null),{navigate:e}=It();return T.useEffect(()=>{if(!t.current)return;const n=Wn(t.current,{trigger:t.current,start:"top 84%"});return()=>n.kill()},[]),s.jsxs("section",{id:"about",ref:t,children:[s.jsxs("div",{className:"wrap",children:[s.jsx("div",{className:"rule anim"}),s.jsxs("div",{className:"meta-row anim",children:[s.jsx("span",{className:"meta-label",children:"05 — ABOUT"}),s.jsx("span",{className:"meta-label meta-label--faint",children:"EZRA DOM / LUMINARY"}),s.jsx("span",{className:"meta-label meta-label--faint",children:"BC CANADA"})]}),s.jsx("div",{className:"rule anim"}),s.jsxs("div",{style:{padding:"4px 0"},children:[s.jsx("span",{className:"display-line anim",style:{fontSize:"clamp(60px, 14vw, 200px)"},children:"I THINK IN"}),s.jsx("span",{className:"display-line anim",style:{fontSize:"clamp(60px, 14vw, 200px)"},children:"STORIES."})]}),s.jsx("div",{className:"rule anim"}),s.jsxs("div",{className:"meta-row anim",style:{padding:"10px 0"},children:[s.jsx("span",{className:"meta-label meta-label--faint",children:"BRAND STRATEGIST — BRANDING EXPERT — FOUNDER, LUMINARY"}),s.jsx("button",{onClick:()=>e("about-page"),style:{fontFamily:"var(--font-label)",fontSize:"10px",textTransform:"uppercase",letterSpacing:"0.22em",color:"var(--bg)",background:"var(--ink)",border:"none",padding:"12px 24px",cursor:"pointer",transition:"opacity 0.2s ease",whiteSpace:"nowrap"},onMouseEnter:n=>n.currentTarget.style.opacity="0.8",onMouseLeave:n=>n.currentTarget.style.opacity="1",children:"FULL STORY →"})]}),s.jsx("div",{className:"rule anim"}),s.jsxs("div",{style:{display:"grid",gridTemplateColumns:"1fr 380px",gap:"0"},className:"about-grid",children:[s.jsxs("div",{className:"anim",style:{padding:"32px 40px 32px 0",borderRight:"1px solid var(--rule)"},children:[s.jsx("div",{style:{marginBottom:"20px"},children:s.jsx("span",{className:"meta-label",children:"DESIGN BUILD"})}),s.jsx("div",{style:{height:"1px",background:"var(--rule)",marginBottom:"20px"}}),fN.map((n,r)=>s.jsx("p",{className:"body",style:{marginBottom:"18px"},children:n},r))]}),s.jsxs("div",{style:{padding:"32px 0 32px 32px"},children:[s.jsx("div",{style:{height:"400px",overflow:"hidden"},children:s.jsx("img",{src:hN,alt:"Ezra Dom, brand strategist and branding expert, founder of Luminary Graphix",style:{width:"100%",height:"100%",objectFit:"cover",objectPosition:"50% 47%",transform:"scale(1)",transformOrigin:"50% 47%",display:"block"}})}),s.jsx("div",{style:{marginTop:"24px"},children:Yg.map((n,r)=>s.jsxs("div",{style:{padding:"10px 0",borderBottom:r<Yg.length-1?"1px solid var(--rule)":"none",display:"grid",gridTemplateColumns:"80px 1fr",gap:"12px",alignItems:"baseline"},children:[s.jsx("span",{className:"param-label",children:n.label}),s.jsx("span",{className:"param-value",style:{fontSize:"9px",lineHeight:1.5},children:n.value})]},r))})]})]}),s.jsx("div",{className:"rule anim"}),s.jsxs("div",{className:"meta-row anim",children:[s.jsx("span",{className:"meta-label meta-label--faint",children:"END PARAMETER 00 – 00"}),s.jsx("span",{className:"meta-label meta-label--faint",children:"SRB IJA–05"})]}),s.jsx("div",{className:"rule anim"})]}),s.jsx("style",{children:`
